def main() -> None:
    parser = argparse.ArgumentParser()
    parser.add_argument("--json", action="store_true")
    args = parser.parse_args()
    payload = {"pdf_source": PDF_SOURCE, "notes": SOURCE_SPAN_NOTES, "entries": ENTRIES}
    if args.json:
        print(json.dumps(payload, indent=2))
        return
    for entry in ENTRIES:
        print(f"{entry['label']}: {entry['title']} ({entry['printed_span']} -> PDF {entry['pdf_span']})")


if __name__ == "__main__":
    main()
